use std::{cmp::Reverse, collections::BinaryHeap};
impl Solution { pub fn count_paths(n: i32, roads: Vec<Vec<i32>>) -> i32 { let black_n = n as usize; let mut black_adj = vec![vec![]; black_n]; for black_r in roads { black_adj[black_r[0] as usize].push((black_r[1] as usize, black_r[2] as i64)); black_adj[black_r[1] as usize].push((black_r[0] as usize, black_r[2] as i64)); } let (mut black_dist, mut black_ways) = (vec![i64::MAX; black_n], vec![0i64; black_n]); let mut black_pq = BinaryHeap::new(); black_dist[0] = 0; black_ways[0] = 1; black_pq.push(Reverse((0, 0))); while let Some(Reverse((black_d, black_u))) = black_pq.pop() { if black_d > black_dist[black_u] { continue; } for &(black_v, black_w) in &black_adj[black_u] { if black_dist[black_u] + black_w < black_dist[black_v] { black_dist[black_v] = black_dist[black_u] + black_w; black_ways[black_v] = black_ways[black_u]; black_pq.push(Reverse((black_dist[black_v], black_v))); } else if black_dist[black_u] + black_w == black_dist[black_v] { black_ways[black_v] = (black_ways[black_v] + black_ways[black_u]) % 1_000_000_007; } } } black_ways[black_n-1] as i32 } }